+  const confirmSelected = (): Promise<void> =>
+    runMutation(async () => {
+      if (sel.length === 0) return;
+      setConfirming(true);
+      try {
+        setKcs(await ktpApi.confirmComponents(subjectId, topicId, sel));
+        setSel([]);
+        await reloadCoverage();
+        flash('Подтемы подтверждены');
+      } finally {
+        setConfirming(false);
+      }
+    });
