+      setKcs(await ktpApi.deleteComponent(subjectId, topicId, kcId));
+      setSel((s) => s.filter((id) => id !== kcId));
+      await reloadCoverage();
+      flash('Подтема удалена');
+    });
+
+  const addManual = (): Promise<void> =>
