+          {loading && <p className="text-xs text-slate-500">Загрузка…</p>}
+          {err && <p className="text-xs text-red-600">{err}</p>}
+          {msg && <p className="text-xs text-green-700">{msg}</p>}
+
+          {/* ── KC: подтверждённые ── */}
+          {confirmedKcs.length > 0 && (
